from pathlib import Path
import json
import re

def verify(workspace_path, external_services_path=None):
    if external_services_path is None:
        return {"pass": False, "score": 0.0, "feedback": "external_services_path is None; cannot check mailbox"}
    mailbox_path = Path(external_services_path) / "mailbox.json"
    if not mailbox_path.exists():
        return {"pass": False, "score": 0.0, "feedback": "mailbox.json not found"}
    with open(mailbox_path) as f:
        data = json.load(f)
    sent_emails = [e for e in data.get("emails", []) if e.get("folder", "").lower() == "sent"]

    # The rubric requires a sent email to Jimmy Rustler containing specific body text.
    # We'll be lenient: normalize whitespace and check key phrases rather than exact match.

    required_phrases = [
        "hi jimmy",
        "thank you for your question",
        "teresa vang",
        "forwarded your question to teresa",
        "teresa.vang@ridgelinegear.com",
        "leave case is moving forward",
        "leave coordinator",
        "leaves@ridgelinegear.com"
    ]

    for email in sent_emails:
        to_addr = (email.get("to_addr") or "").lower()
        if "jimmy" in to_addr or "rustler" in to_addr:
            body = (email.get("body_text") or "")
            # Normalize: collapse whitespace, lower-case for comparison
            body_normalized = re.sub(r'\s+', ' ', body).lower().strip()

            missing = []
            for phrase in required_phrases:
                phrase_normalized = re.sub(r'\s+', ' ', phrase).lower().strip()
                if phrase_normalized not in body_normalized:
                    missing.append(phrase)

            if not missing:
                return {"pass": True, "score": 1.0, "feedback": f"Found sent email to Jimmy Rustler with all required content. to_addr={email.get('to_addr')}, body snippet: {body[:300]}"}
            else:
                # Still allow a pass if most key phrases are present (be lenient)
                # The rubric says "containing" the text, but we allow minor variations
                match_ratio = (len(required_phrases) - len(missing)) / len(required_phrases)
                if match_ratio >= 0.75:
                    return {"pass": True, "score": match_ratio, "feedback": f"Found sent email to Jimmy Rustler with most required content ({match_ratio:.0%} match). Missing: {missing}. to_addr={email.get('to_addr')}, body snippet: {body[:300]}"}
                else:
                    return {"pass": False, "score": match_ratio * 0.5, "feedback": f"Found sent email to Jimmy Rustler but missing key phrases: {missing}. Match ratio: {match_ratio:.0%}. Body snippet: {body[:300]}"}

    # No email to Jimmy found
    jimmy_emails = [e for e in sent_emails if "jimmy" in (e.get("to_addr") or "").lower() or "rustler" in (e.get("to_addr") or "").lower()]
    if jimmy_emails:
        bodies = [(e.get("body_text") or "")[:150] for e in jimmy_emails]
        return {"pass": False, "score": 0.0, "feedback": f"Found {len(jimmy_emails)} sent email(s) to Jimmy Rustler but none contained the required content. Body snippets: {bodies}"}
    return {"pass": False, "score": 0.0, "feedback": f"No sent email found to Jimmy Rustler. Sent to_addrs: {[e.get('to_addr') for e in sent_emails]}"}

